import { PRESET_DOMAINS } from "./utils";

const STORAGE_KEY = "custom_domains";

export interface Domain {
  name: string;
  icon: string;
  color: string;
}

export const UNCATEGORIZED: Domain = { name: "未分类", icon: "📦", color: "#78716c" };

function getStoredDomains(): Domain[] {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      const parsed = JSON.parse(stored);
      if (Array.isArray(parsed) && parsed.length > 0) {
        return parsed;
      }
    }
  } catch {
    /* ignore parse errors */
  }
  return [...PRESET_DOMAINS];
}

export function getDomains(): Domain[] {
  return [...getStoredDomains(), UNCATEGORIZED];
}

export function saveDomains(doms: Domain[]): void {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(doms));
}

export function resetDomains(): void {
  localStorage.removeItem(STORAGE_KEY);
}

